/**
 * Regression test for non-legacy mail content decryption failure.
 * Tests the bug where owner-encrypted session keys are not propagated
 * when loading related entities (MailBody, MailDetailsBlob, etc.).
 */

import { describe, it, expect, beforeEach, afterEach, jest } from "@jest/globals"
import type { Mail, MailDetailsBlob, MailDetailsDraft } from "../src/api/entities/tutanota/TypeRefs"
import {
	createMail,
	createMailDetailsBlob,
	createMailDetailsDraft,
	createMailDetails,
	MailDetailsBlobTypeRef,
	MailDetailsDraftTypeRef,
	MailTypeRef,
} from "../src/api/entities/tutanota/TypeRefs"
import { MailState } from "../src/api/common/TutanotaConstants"
import { EntityClient } from "../src/api/common/EntityClient"
import type { EntityRestInterface } from "../src/api/worker/rest/EntityRestClient"
import { SessionKeyNotFoundError } from "../src/api/common/error/SessionKeyNotFoundError"
import { loadMailDetails } from "../src/mail/model/MailUtils"

/**
 * Mock EntityRestInterface that simulates the bug:
 * When loading multiple entities (like MailDetailsBlob), the session key
 * from the parent mail object is not passed through, causing decryption to fail.
 */
class MockEntityRestClient implements EntityRestInterface {
	private sessionKeyCache: Map<string, Uint8Array> = new Map()

	async load<T>(
		typeRef: any,
		id: any,
		queryParameters?: any,
		extraHeaders?: any,
		ownerKey?: any
	): Promise<T> {
		// For Mail entities, return the mail with ownerEncSessionKey
		if (typeRef.type === "Mail") {
			const [listId, elementId] = id
			const mail = createMail({
				_id: [listId, elementId],
				_ownerGroup: "group1",
				_ownerEncSessionKey: "encryptedSessionKey123", // Simulating owner-encrypted session key
				_type: MailTypeRef,
				subject: "Test Mail",
				state: MailState.RECEIVED,
				unread: false,
				sender: { address: "sender@example.com", name: "Sender" },
				toRecipients: [],
				ccRecipients: [],
				bccRecipients: [],
				replyTos: [],
				attachments: [],
				firstRecipient: null,
				recipientCount: "0",
				mailDetails: [listId, "mailDetails123"], // Reference to MailDetailsBlob
				headers: null,
				conversationEntry: null,
			}) as any
			return mail as T
		}

		// For MailDetailsBlob, return the entity WITHOUT session key information
		// This simulates the actual behavior where the related entity doesn't have
		// the session key, expecting it to be resolved from the parent entity
		if (typeRef.type === "MailDetailsBlob") {
			const [listId, elementId] = id
			const mailDetailsBlob = createMailDetailsBlob({
				_id: [listId, elementId],
				_ownerGroup: "group1",
				// Note: NOT setting _ownerEncSessionKey here - this is the problem!
				// The session key from the parent Mail object is not available here
				_type: MailDetailsBlobTypeRef,
				details: createMailDetails({
					bodyText: "Secret content",
					bodyHtml: "<p>Secret content</p>",
					headers: null,
					attachments: [],
					calendarEvent: null,
				}),
			}) as any
			return mailDetailsBlob as T
		}

		throw new Error(`Unexpected type: ${typeRef.type}`)
	}

	async loadRange<T>(
		typeRef: any,
		listId: string,
		start: string,
		count: number,
		reverse: boolean
	): Promise<T[]> {
		return []
	}

	async loadMultiple<T>(typeRef: any, listId: string | null, elementIds: string[]): Promise<T[]> {
		// This is where the bug manifests!
		// When loading multiple MailDetailsBlob entities, the session key from the
		// parent Mail object is NOT passed through.
		// The loadMultiple method tries to resolve the session key from each entity itself,
		// but the MailDetailsBlob doesn't have _ownerEncSessionKey (it's owner-encrypted
		// with a key stored only in the parent Mail), so decryption fails.

		const results: T[] = []
		for (const elementId of elementIds) {
			if (typeRef.type === "MailDetailsBlob") {
				const mailDetailsBlob = createMailDetailsBlob({
					_id: [listId, elementId],
					_ownerGroup: "group1",
					// Missing _ownerEncSessionKey - THE ROOT CAUSE OF THE BUG!
					// The session key for decrypting this entity exists only in the parent Mail's
					// _ownerEncSessionKey field, but it's not being passed here.
					_type: MailDetailsBlobTypeRef,
					details: createMailDetails({
						bodyText: "Secret content",
						bodyHtml: "<p>Secret content</p>",
						headers: null,
						attachments: [],
						calendarEvent: null,
					}),
				}) as any

				// Simulate the decryption failure that would occur in the real code
				// When instanceMapper tries to decrypt this entity, it calls
				// CryptoFacade.resolveSessionKey() which:
				// 1. Checks if bucketKey exists (no)
				// 2. Checks if _ownerEncSessionKey exists (no) <- BUG: should use parent's key
				// 3. Tries to load permissions (might not exist or might fail)
				// Result: SessionKeyNotFoundError is thrown

				results.push(mailDetailsBlob as T)
			}
		}
		return results
	}

	async setup<T>(listId: string | null, instance: T, extraHeaders?: any, options?: any): Promise<string> {
		return "newId"
	}

	async setupMultiple<T>(listId: string | null, instances: T[]): Promise<string[]> {
		return instances.map((_, i) => `id${i}`)
	}

	async update<T>(instance: T, ownerKey?: any): Promise<void> {
		// No-op
	}

	async erase<T>(instance: T): Promise<void> {
		// No-op
	}

	async entityEventsReceived(batch: any): Promise<any[]> {
		return []
	}
}

describe("Regression Test: Non-legacy mail decryption failure", () => {
	let mockRestClient: MockEntityRestClient
	let entityClient: EntityClient

	beforeEach(() => {
		mockRestClient = new MockEntityRestClient()
		entityClient = new EntityClient(mockRestClient)
	})

	it("should demonstrate the bug where MailDetailsBlob cannot be decrypted without parent session key", async () => {
		// Create a non-legacy mail with owner-encrypted session key
		const mail = createMail({
			_id: ["list1", "mail1"],
			_ownerGroup: "group1",
			_ownerEncSessionKey: "encryptedSessionKey123", // Key to decrypt this mail's content
			_type: MailTypeRef,
			subject: "Test Mail",
			state: MailState.RECEIVED,
			unread: false,
			sender: { address: "sender@example.com", name: "Sender" },
			toRecipients: [],
			ccRecipients: [],
			bccRecipients: [],
			replyTos: [],
			attachments: [],
			firstRecipient: null,
			recipientCount: "0",
			mailDetails: ["list1", "mailDetails123"], // Reference to MailDetailsBlob
			headers: null,
			conversationEntry: null,
		}) as Mail

		// Try to load the mail details
		// This should fail because:
		// 1. The mail has _ownerEncSessionKey which is used to decrypt the mail itself
		// 2. The MailDetailsBlob ALSO uses the same session key (same as mail)
		// 3. But when loadMultiple loads the MailDetailsBlob, it doesn't have access to the mail's _ownerEncSessionKey
		// 4. So it tries to resolve the session key from the MailDetailsBlob itself
		// 5. The MailDetailsBlob doesn't have _ownerEncSessionKey, so decryption fails

		let errorThrown = false
		let errorMessage = ""

		try {
			await loadMailDetails(entityClient, mail)
		} catch (e: any) {
			errorThrown = true
			errorMessage = e.message || String(e)
		}

		// The test demonstrates the bug: this should NOT throw an error
		// because the session key is available from the parent mail object
		// However, in the buggy implementation, it DOES throw because the
		// session key is not propagated from the parent to the child entity
		expect(errorThrown).toBe(true)
		expect(errorMessage).toContain("could not resolve session key") || expect(errorMessage).toContain("Missing")
	})

	it("should fail to load MailDetailsBlob via loadMultiple without parent session key propagation", async () => {
		// This test specifically demonstrates the bug in the loadMultiple path
		const mailDetailsBlobIds = ["mailDetails123"]

		// When calling loadMultiple on MailDetailsBlob without the parent mail's session key,
		// the decryption should fail
		const results = await entityClient.loadMultiple(MailDetailsBlobTypeRef, "list1", mailDetailsBlobIds)

		// The entities are loaded, but they cannot be decrypted properly
		// because the session key is not available
		expect(results).toHaveLength(1)

		// In a real scenario, the decryption would have failed in the _decryptMapAndMigrate
		// function because it cannot resolve the session key for the entity
		// This is the core of the bug: loadMultiple doesn't accept a session key parameter
		// and doesn't get one from the parent entity
	})

	it("should demonstrate how session key propagation should work for non-legacy mails", async () => {
		// This test documents the expected behavior:
		// When loading related entities of a mail, the parent mail's session key
		// should be propagated to the related entity loading.

		const mail = createMail({
			_id: ["list1", "mail1"],
			_ownerGroup: "group1",
			_ownerEncSessionKey: "encryptedSessionKey123",
			_type: MailTypeRef,
			subject: "Test Mail",
			state: MailState.RECEIVED,
			unread: false,
			sender: { address: "sender@example.com", name: "Sender" },
			toRecipients: [],
			ccRecipients: [],
			bccRecipients: [],
			replyTos: [],
			attachments: [],
			firstRecipient: null,
			recipientCount: "0",
			mailDetails: ["list1", "mailDetails123"],
			headers: null,
			conversationEntry: null,
		}) as Mail

		// The fix would require one of:
		// 1. Passing the session key explicitly to loadMultiple()
		// 2. Caching the session key in CryptoFacade when the parent mail is loaded
		// 3. Deriving the session key from the parent entity's ownerEncSessionKey

		// Currently, none of these work correctly for non-legacy mails with
		// owner-encrypted session keys, causing the decryption to fail.
		expect(mail._ownerEncSessionKey).toBe("encryptedSessionKey123")
		expect(mail.mailDetails).toEqual(["list1", "mailDetails123"])

		// The bug: loadMultiple has no way to receive the parent mail's session key
		// and cannot decrypt the MailDetailsBlob without it
	})
})

/**
 * Regression test for non-legacy mail content decryption failure.
 *
 * Bug: Users with non-legacy (new permission model) mails experience failures
 * when opening emails because the owner-encrypted session key is not propagated
 * when loading related entities like MailBody, MailDetailsBlob, and MailDetailsDraft.
 *
 * Root cause: When loadMailDetails() is called, it loads related entities via
 * loadMultiple(), but doesn't pass the session key from the parent Mail object.
 * The CryptoFacade.resolveSessionKey() method then fails to decrypt the entity
 * because the session key information is not available.
 *
 * This test demonstrates the bug in the loadMailDetails -> loadMultiple ->
 * _decryptMapAndMigrate -> resolveSessionKey call chain.
 */

import type { Mail, MailDetailsBlob } from "../src/api/entities/tutanota/TypeRefs"
import {
	createMail,
	createMailDetailsBlob,
	createMailDetails,
	MailDetailsBlobTypeRef,
	MailTypeRef,
} from "../src/api/entities/tutanota/TypeRefs"
import { MailState } from "../src/api/common/TutanotaConstants"
import { EntityClient } from "../src/api/common/EntityClient"
import type { EntityRestInterface, EntityRestClient } from "../src/api/worker/rest/EntityRestClient"
import { elementIdPart, listIdPart } from "../src/api/common/utils/EntityUtils"

/**
 * Test implementation demonstrating the session key propagation bug.
 *
 * The core issue is in MailUtils.ts loadMailDetails() function:
 * ```typescript
 * export async function loadMailDetails(entityClient: EntityClient, mail: Mail): Promise<MailWrapper> {
 *   ...
 *   } else {
 *     const mailDetailsId = neverNull(mail.mailDetails)
 *     return entityClient
 *       .loadMultiple(MailDetailsBlobTypeRef, listIdPart(mailDetailsId), [elementIdPart(mailDetailsId)])
 *       .then((d) => MailWrapper.details(mail, d[0].details))
 *   }
 * }
 * ```
 *
 * This calls loadMultiple() without any way to pass the mail's session key.
 * The underlying EntityRestClient.loadMultiple() calls _handleLoadMultipleResult()
 * which calls _decryptMapAndMigrate() which tries to resolve the session key
 * from the entity itself via CryptoFacade.resolveSessionKey().
 *
 * For non-legacy mails with owner-encrypted session keys:
 * 1. The MailDetailsBlob entity is encrypted with the same session key as the Mail
 * 2. But MailDetailsBlob doesn't have _ownerEncSessionKey (it's owner-encrypted)
 * 3. So CryptoFacade.resolveSessionKey() has no way to decrypt it
 * 4. It throws SessionKeyNotFoundError
 */
describe("Regression: Non-legacy mail decryption failure", () => {
	// Mock EntityRestClient that simulates the real behavior where
	// MailDetailsBlob entities don't have their own _ownerEncSessionKey
	class BuggyEntityRestClientMock implements EntityRestInterface {
		private mailDetailsCache: Map<string, MailDetailsBlob> = new Map()

		async load<T extends any>(
			typeRef: any,
			id: any,
			queryParameters?: any,
			extraHeaders?: any,
			ownerKey?: any
		): Promise<T> {
			if (typeRef.type === "Mail") {
				const [listId, elementId] = Array.isArray(id) ? id : [id]
				return createMail({
					_id: [listId, elementId],
					_ownerGroup: "group1",
					// This is the key that should be used to decrypt mailDetails!
					_ownerEncSessionKey: "encryptedMailSessionKey",
					_type: MailTypeRef,
					subject: "Test Mail",
					state: MailState.RECEIVED,
					unread: false,
					sender: { address: "sender@example.com", name: "Sender" },
					toRecipients: [],
					ccRecipients: [],
					bccRecipients: [],
					replyTos: [],
					attachments: [],
					firstRecipient: null,
					recipientCount: "0",
					mailDetails: [listId, "mailDetails123"],
					headers: null,
					conversationEntry: null,
				}) as unknown as T
			}
			throw new Error(`Unexpected type: ${typeRef.type}`)
		}

		async loadRange<T>(
			typeRef: any,
			listId: string,
			start: string,
			count: number,
			reverse: boolean
		): Promise<T[]> {
			return []
		}

		async loadMultiple<T>(typeRef: any, listId: string | null, elementIds: string[]): Promise<T[]> {
			// THIS IS WHERE THE BUG MANIFESTS!
			// loadMultiple has no way to receive the session key from the parent Mail
			if (typeRef.type === "MailDetailsBlob") {
				const results: T[] = []
				for (const elementId of elementIds) {
					// Create MailDetailsBlob WITHOUT _ownerEncSessionKey
					// In the real code, this entity would need the parent mail's session key to decrypt
					const blob = createMailDetailsBlob({
						_id: [listId, elementId],
						_ownerGroup: "group1",
						// BUG: This entity should have access to the parent mail's _ownerEncSessionKey,
						// but there's no mechanism to pass it through loadMultiple
						// _ownerEncSessionKey: "encryptedMailSessionKey", // <- MISSING!
						_type: MailDetailsBlobTypeRef,
						details: createMailDetails({
							bodyText: "Secret email body",
							bodyHtml: "<p>Secret email body</p>",
							headers: null,
							attachments: [],
							calendarEvent: null,
						}),
					})
					results.push(blob as T)
					// In real code, when this entity is passed to CryptoFacade.resolveSessionKey(),
					// it would try to:
					// 1. Check sessionKeyCache (empty - no cache entry)
					// 2. Check if entity has bucketKey (no)
					// 3. Check if entity has _ownerEncSessionKey (no) <- FAILS HERE
					// 4. Try to load permissions (might not exist for non-legacy mails)
					// Result: SessionKeyNotFoundError
				}
				return results
			}
			throw new Error(`Unexpected type: ${typeRef.type}`)
		}

		async setup<T>(listId: string | null, instance: T): Promise<string> {
			return "newId"
		}

		async setupMultiple<T>(listId: string | null, instances: T[]): Promise<string[]> {
			return instances.map((_, i) => `id${i}`)
		}

		async update<T>(instance: T): Promise<void> {
			// No-op
		}

		async erase<T>(instance: T): Promise<void> {
			// No-op
		}

		async entityEventsReceived(batch: any): Promise<any[]> {
			return []
		}
	}

	test("demonstrates missing session key propagation for non-legacy mail with owner-encrypted keys", async () => {
		const mockRestClient = new BuggyEntityRestClientMock()
		const entityClient = new EntityClient(mockRestClient)

		// Create a non-legacy mail with owner-encrypted session key
		const mail = createMail({
			_id: ["list1", "mail1"],
			_ownerGroup: "group1",
			_ownerEncSessionKey: "encryptedMailSessionKey",
			_type: MailTypeRef,
			subject: "Test Mail",
			state: MailState.RECEIVED,
			unread: false,
			sender: { address: "sender@example.com", name: "Sender" },
			toRecipients: [],
			ccRecipients: [],
			bccRecipients: [],
			replyTos: [],
			attachments: [],
			firstRecipient: null,
			recipientCount: "0",
			mailDetails: ["list1", "mailDetails123"],
			headers: null,
			conversationEntry: null,
		}) as Mail

		// Try to load the MailDetailsBlob associated with this mail
		// This simulates what loadMailDetails() does for non-legacy mails
		const listId = mail.mailDetails[0]
		const elementId = mail.mailDetails[1]

		const mailDetailsBlobs = await entityClient.loadMultiple(
			MailDetailsBlobTypeRef,
			listId,
			[elementId]
		)

		// The test verifies that:
		// 1. The entity IS loaded (no exception from loadMultiple itself)
		expect(mailDetailsBlobs).toHaveLength(1)

		// 2. But the entity doesn't have the session key information needed for decryption
		const mailDetailsBlob = mailDetailsBlobs[0]
		expect(mailDetailsBlob._id).toEqual(["list1", "mailDetails123"])

		// 3. The crucial issue: the entity doesn't have _ownerEncSessionKey
		// In real code, when CryptoFacade tries to decrypt this, it will fail
		// because the session key from the parent mail is NOT propagated
		expect(mailDetailsBlob._ownerEncSessionKey).toBeUndefined()

		// 4. The parent mail HAS the session key
		expect(mail._ownerEncSessionKey).toBe("encryptedMailSessionKey")

		// 5. But there's no way for the decryption code to access it
		// This is the ROOT CAUSE of the bug
	})

	test("demonstrates that loadMultiple cannot receive session key from parent entity", async () => {
		const mockRestClient = new BuggyEntityRestClientMock()
		const entityClient = new EntityClient(mockRestClient)

		// This test shows that the EntityClient.loadMultiple signature doesn't
		// support passing a session key or ownerKey parameter

		// The method signature is:
		// loadMultiple<T extends SomeEntity>(typeRef: TypeRef<T>, listId: Id | null, elementIds: Id[]): Promise<T[]>

		// There's no parameter for:
		// - ownerKey (unlike load and update methods which have this parameter)
		// - sessionKey (no such parameter exists)

		// This is the structural problem that makes it impossible to pass the
		// parent mail's session key to loadMultiple

		const emailDetailsIds = ["mailDetails123"]

		// No way to pass the mail's session key here:
		const mailDetails = await entityClient.loadMultiple(
			MailDetailsBlobTypeRef,
			"list1",
			emailDetailsIds
			// <- No ownerKey parameter possible here!
		)

		expect(mailDetails).toHaveLength(1)
		expect(mailDetails[0]._ownerEncSessionKey).toBeUndefined()
	})

	test("documents the expected behavior that should be fixed", async () => {
		const mockRestClient = new BuggyEntityRestClientMock()
		const entityClient = new EntityClient(mockRestClient)

		const mail = createMail({
			_id: ["list1", "mail1"],
			_ownerGroup: "group1",
			_ownerEncSessionKey: "encryptedMailSessionKey",
			_type: MailTypeRef,
			subject: "Test Mail",
			state: MailState.RECEIVED,
			unread: false,
			sender: { address: "sender@example.com", name: "Sender" },
			toRecipients: [],
			ccRecipients: [],
			bccRecipients: [],
			replyTos: [],
			attachments: [],
			firstRecipient: null,
			recipientCount: "0",
			mailDetails: ["list1", "mailDetails123"],
			headers: null,
			conversationEntry: null,
		}) as Mail

		// The fix would need to:
		// Option 1: Pass ownerKey to loadMultiple
		//   await entityClient.loadMultiple(..., ownerKey: mail._ownerEncSessionKey)
		//   But this requires API change to all loadMultiple calls

		// Option 2: Cache the session key when mail is loaded
		//   CryptoFacade caches the mailDetails session key when mail is loaded
		//   But the cache might not be shared between different EntityClient instances

		// Option 3: Decrypt at the calling site
		//   Instead of trying to decrypt inside loadMultiple,
		//   loadMailDetails could handle decryption knowing it has the session key

		// Option 4: Store _ownerEncSessionKey on MailDetailsBlob
		//   When MailDetailsBlob is created, include the parent's encrypted session key
		//   But this changes the entity model

		// For now, the test documents that the current implementation fails
		// because there's no mechanism to propagate session keys through loadMultiple

		// Verify the bug exists
		const result = await entityClient.loadMultiple(
			MailDetailsBlobTypeRef,
			mail.mailDetails[0],
			[mail.mailDetails[1]]
		)

		expect(result[0]._ownerEncSessionKey).toBeUndefined()
		expect(mail._ownerEncSessionKey).toBe("encryptedMailSessionKey")
		// These are different, and there's no way to fix it with current API
	})
})

